                                                                                                                                    end)

                                                                                                                                    -- ===== ФУНКЦИИ =====

                                                                                                                                    local function getClosestMob()
                                                                                                                                        local closestMob = nil
                                                                                                                                            local closestDistance = math.huge
                                                                                                                                                
                                                                                                                                                    for _, mob in pairs(workspace:GetChildren()) do
                                                                                                                                                            if mob:FindFirstChild("Humanoid") and mob:FindFirstChild("HumanoidRootPart") then
                                                                                                                                                                        if mob.Humanoid.Health > 0 and not mob:IsA("Player") then
                                                                                                                                                                                        local distance = (mob.HumanoidRootPart.Position - char.HumanoidRootPart.Position).Magnitude
                                                                                                                                                                                                        if distance < closestDistance and distance < Settings.FarmRadius then
                                                                                                                                                                                                                            closestMob = mob
                                                                                                                                                                                                                                                closestDistance = distance
                                                                                                                                                                                                                                                                end
                                                                                                                                                                                                                                                                            end
                                                                                                                                                                                                                                                                                    end
                                                                                                                                                                                                                                                                                        end
                                                                                                                                                                                                                                                                                            
                                                                                                                                                                                                                                                                                                return closestMob
                                                                                                                                                                                                                                                                                                end

                                                                                                                                                                                                                                                                                                local function findQuestNPC()
                                                                                                                                                                                                                                                                                                    for _, npc in pairs(workspace:GetChildren()) do
                                                                                                                                                                                                                                                                                                            if npc:FindFirstChild("Humanoid") and npc.Name:find("Quest") then
                                                                                                                                                                                                                                                                                                                        return npc
                                                                                                                                                                                                                                                                                                                                end
                                                                                                                                                                                                                                                                                                                                    end
                                                                                                                                                                                                                                                                                                                                        return nil
                                                                                                                                                                                                                                                                                                                                        end

                                                                                                                                                                                                                                                                                                                                        local function attackMob(mob)
                                                                                                                                                                                                                                                                                                                                            if not mob then return end
                                                                                                                                                                                                                                                                                                                                                
                                                                                                                                                                                                                                                                                                                                                    char.HumanoidRootPart.CFrame = CFrame.new(char.HumanoidRootPart.Position, mob.HumanoidRootPart.Position)
                                                                                                                                                                                                                                                                                                                                                        
                                                                                                                                                                                                                                                                                                                                                            local remote = game:GetService("ReplicatedStorage"):FindFirstChild("Remotes"):FindFirstChild("Attack")
                                                                                                                                                                                                                                                                                                                                                                if remote then
                                                                                                                                                                                                                                                                                                                                                                        remote:FireServer(mob)
                                                                                                                                                                                                                                                                                                                                                                            end
                                                                                                                                                                                                                                                                                                                                                                            end

                                                                                                                                                                                                                                                                                                                                                                            local function collectDrops()
                                                                                                                                                                                                                                                                                                                                                                                for _, drop in pairs(workspace:GetChildren()) do
                                                                                                                                                                                                                                                                                                                                                                                        if drop:IsA("Tool") or drop:IsA("Part") and drop.Name:find("Drop") then
                                                                                                                                                                                                                                                                                                                                                                                                    if drop:FindFirstChild("ClickDetector") then
                                                                                                                                                                                                                                                                                                                                                                                                                    fireclickdetector(drop.ClickDetector)
                                                                                                                                                                                                                                                                                                                                                                                                                                end
                                                                                                                                                                                                                                                                                                                                                                                                                                        end
                                                                                                                                                                                                                                                                                                                                                                                                                                            end
                                                                                                                                                                                                                                                                                                                                                                                                                                            end

                                                                                                                                                                                                                                                                                                                                                                                                                                            -- ===== ОСНОВНОЙ ЦИКЛ =====

                                                                                                                                                                                                                                                                                                                                                                                                                                            RunService.Heartbeat:Connect(function()
                                                                                                                                                                                                                                                                                                                                                                                                                                                if not char or not char:FindFirstChild("HumanoidRootPart") then return end
                                                                                                                                                                                                                                                                                                                                                                                                                                                    
                                                                                                                                                                                                                                                                                                                                                                                                                                                        if Settings.AutoFarm then
                                                                                                                                                                                                                                                                                                                                                                                                                                                                local mob = getClosestMob()
                                                                                                                                                                                                                                                                                                                                                                                                                                                                        if mob then
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    attackMob(mob)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            end
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                end
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        if Settings.AutoCollect then
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                collectDrops()
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    end
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            if Settings.AutoQuest then
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    local npc = findQuestNPC()
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            if npc then
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        char.HumanoidRootPart.CFrame = npc.HumanoidRootPart.CFrame + Vector3.new(0, 0, 5)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                end
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    end
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            if Settings.AutoHeal and char.Humanoid.Health < Settings.HealThreshold then
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    local healTool = player.Backpack:FindFirstChild("Heal")
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            if healTool then
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        char.Humanoid:EquipTool(healTool)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    healTool:Activate()
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            end
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                end
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                end)

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                -- ===== ГОРЯЧИЕ КЛАВИШИ =====

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                UserInputService.InputBegan:Connect(function(input, gameProcessed)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    if gameProcessed then return end
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            if input.KeyCode == Enum.KeyCode.F3 then
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    MainFrame.Visible = not MainFrame.Visible
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        elseif input.KeyCode == Enum.KeyCode.F1 then
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                Settings.AutoFarm = not Settings.AutoFarm
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    elseif input.KeyCode == Enum.KeyCode.F2 then
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            Settings.AutoQuest = not Settings.AutoQuest
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                end
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                end)

