                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                print("✅ KIRILGAYXXX ЗАГРУЖЕН!")
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                print("📌 F1 - AutoFarm | F2 - AutoQuest | F3 - Меню")